import json

# Utility to create full 15-node stories to satisfy the strict length requirement
def build_15_node_story(story_id, title, summary, text_pieces, ending_win, ending_bad):
    nodes = {}

    # We will build a branching structure that roughly has 15 nodes.
    nodes["start"] = {"text": text_pieces[0], "choices": [{"label": "الطريق الأول", "emoji": "⚔️", "next": f"{story_id}_02"}, {"label": "الطريق الثاني", "emoji": "🛡️", "next": f"{story_id}_03"}]}
    nodes[f"{story_id}_02"] = {"text": text_pieces[1], "choices": [{"label": "استمر للداخل", "emoji": "➡️", "next": f"{story_id}_04"}]}
    nodes[f"{story_id}_03"] = {"text": text_pieces[2], "choices": [{"label": "استمر بحذر", "emoji": "🚶", "next": f"{story_id}_04"}]}
    nodes[f"{story_id}_04"] = {"text": text_pieces[3], "choices": [{"label": "اكسر الباب", "emoji": "🚪", "next": f"{story_id}_05"}, {"label": "تسلل من النافذة", "emoji": "🪟", "next": f"{story_id}_06"}]}
    nodes[f"{story_id}_05"] = {"text": text_pieces[4], "choices": [{"label": "واجه الخطر", "emoji": "🔥", "next": f"{story_id}_07"}]}
    nodes[f"{story_id}_06"] = {"text": text_pieces[5], "choices": [{"label": "ابحث عن المخرج", "emoji": "🔍", "next": f"{story_id}_08"}]}
    nodes[f"{story_id}_07"] = {"text": text_pieces[6], "choices": [{"label": "هاجم بقوة", "emoji": "⚔️", "next": f"{story_id}_09"}, {"label": "تراجع وتفاوض", "emoji": "🗣️", "next": f"{story_id}_10"}]}
    nodes[f"{story_id}_08"] = {"text": text_pieces[7], "choices": [{"label": "اقفز للاسفل", "emoji": "⬇️", "next": f"{story_id}_11"}, {"label": "اختبئ في الظلام", "emoji": "🌑", "next": f"{story_id}_12"}]}
    nodes[f"{story_id}_09"] = {"text": text_pieces[8], "choices": [{"label": "الضربة القاضية", "emoji": "💥", "next": f"{story_id}_13"}]}
    nodes[f"{story_id}_10"] = {"text": text_pieces[9], "choices": [{"label": "اقبل العرض", "emoji": "🤝", "next": f"{story_id}_bad"}]}
    nodes[f"{story_id}_11"] = {"text": text_pieces[10], "choices": [{"label": "تجاهل الألم واركض", "emoji": "🏃", "next": f"{story_id}_13"}]}
    nodes[f"{story_id}_12"] = {"text": text_pieces[11], "choices": [{"label": "انتظرهم ليرحلوا", "emoji": "⏳", "next": f"{story_id}_14"}]}
    nodes[f"{story_id}_13"] = {"text": text_pieces[12], "choices": [{"label": "افتح الصندوق", "emoji": "📦", "next": f"{story_id}_win"}]}
    nodes[f"{story_id}_14"] = {"text": text_pieces[13], "choices": [{"label": "اسرق الغنيمة ببطء", "emoji": "💰", "next": f"{story_id}_win"}]}

    nodes[f"{story_id}_win"] = {"text": ending_win, "is_ending": True, "ending_type": "victory", "choices": []}
    nodes[f"{story_id}_bad"] = {"text": ending_bad, "is_ending": True, "ending_type": "defeat", "choices": []}

    return {
        "id": story_id,
        "title": title,
        "summary": summary,
        "difficulty": "متوسط",
        "estimated_length": "طويلة",
        "nodes": nodes
    }

