def build_15_node_solo(story_id, title, summary, perspectives):
    nodes = {}
    for i, p in enumerate(perspectives):
        start_id = p["start_node"]
        prefix = p["id"]
        # Basic 15 node tree per perspective
        nodes[start_id] = {"text": f"أنت {p['label']}. {summary} ماذا ستفعل الآن؟", "choices": [{"label": "اكتشف الحقيقة", "emoji": "🔍", "next": f"{prefix}_02"}, {"label": "تجاهل الخطر", "emoji": "🚶", "next": f"{prefix}_03"}]}
        nodes[f"{prefix}_02"] = {"text": "تجد دليلاً غريباً على الطاولة.", "choices": [{"label": "افحصه بدقة", "emoji": "👁️", "next": f"{prefix}_04"}]}
        nodes[f"{prefix}_03"] = {"text": "تحاول التجاهل لكن الخوف يتملكك.", "choices": [{"label": "عد أدراجك", "emoji": "🔙", "next": f"{prefix}_04"}]}
        nodes[f"{prefix}_04"] = {"text": "تسمع صوتاً خلف الباب.", "choices": [{"label": "افتح الباب بقوة", "emoji": "🚪", "next": f"{prefix}_05"}, {"label": "اختبئ في الزاوية", "emoji": "🌑", "next": f"{prefix}_06"}]}
        nodes[f"{prefix}_05"] = {"text": "تجد شخصاً غريباً يقف هناك.", "choices": [{"label": "هاجمه", "emoji": "⚔️", "next": f"{prefix}_07"}]}
        nodes[f"{prefix}_06"] = {"text": "الشخص الغريب يدخل ويبحث عن شيء.", "choices": [{"label": "راقبه بصمت", "emoji": "🤫", "next": f"{prefix}_08"}]}
        nodes[f"{prefix}_07"] = {"text": "تشتبك معه ويسقط السلاح.", "choices": [{"label": "التقط السلاح", "emoji": "🔫", "next": f"{prefix}_09"}, {"label": "اهرب", "emoji": "🏃", "next": f"{prefix}_bad"}]}
        nodes[f"{prefix}_08"] = {"text": "يجد ضالته ويحاول المغادرة.", "choices": [{"label": "اعترض طريقه", "emoji": "✋", "next": f"{prefix}_10"}]}
        nodes[f"{prefix}_09"] = {"text": "الآن السلاح في يدك.", "choices": [{"label": "هدده ليعترف", "emoji": "🗣️", "next": f"{prefix}_11"}]}
        nodes[f"{prefix}_10"] = {"text": "يضربك ويهرب مسرعاً.", "choices": [{"label": "طاردة في الخارج", "emoji": "🏃", "next": f"{prefix}_12"}]}
        nodes[f"{prefix}_11"] = {"text": "يعترف بكل تفاصيل الجريمة المروعة.", "choices": [{"label": "سلمه للعدالة", "emoji": "👮", "next": f"{prefix}_win"}]}
        nodes[f"{prefix}_12"] = {"text": "يختفي في الظلام وتفقد أثره.", "choices": [{"label": "ابحث عن أدلة أخرى تركها", "emoji": "🔦", "next": f"{prefix}_13"}]}
        nodes[f"{prefix}_13"] = {"text": "تجد هاتفه المحمول سقط منه.", "choices": [{"label": "افتح الرسائل النصية", "emoji": "📱", "next": f"{prefix}_14"}]}
        nodes[f"{prefix}_14"] = {"text": "الرسائل تكشف عن مؤامرة كاملة تورط شخصيات كبرى.", "choices": [{"label": "انشر الحقيقة للصحافة وانهِ الأمر", "emoji": "📰", "next": f"{prefix}_win"}]}

        nodes[f"{prefix}_win"] = {"text": "نجحت في مهامك وحققت مرادك بامتياز. لقد انتصرت بعد ليلة عصيبة.", "is_ending": True, "ending_type": "victory", "choices": []}
        nodes[f"{prefix}_bad"] = {"text": "لقد أخطأت التصرف وخسرت كل شيء. النهاية قاسية ومؤلمة جداً.", "is_ending": True, "ending_type": "defeat", "choices": []}
    return {
        "id": story_id,
        "title": title,
        "summary": summary,
        "difficulty": "متوسط",
        "estimated_length": "طويلة",
        "perspectives": perspectives,
        "nodes": nodes
    }

